(window.webpackJsonp=window.webpackJsonp||[]).push([[190],{817:function(n,t){n.exports="\x3c!-- \ntitle: SQLite\nsort: \n--\x3e \n\n```bash\n# 创建数据库\n$ sqlite3 <DBname.db>\n.open <DBname.db>\n\n# 信息\n.databases\n.tables\n.show\n\n# 数据类型\nREAL\t# 浮点数\n\n# 命令\nsqlite> CREATE TABLE COMPANY(\n   ID INT PRIMARY KEY     NOT NULL,\n   NAME           TEXT    NOT NULL,\n   AGE            INT     NOT NULL,\n   ADDRESS        CHAR(50),\n   SALARY         REAL\n);\n\n# 导出为文本文件\n$ sqlite3 testDB.db .dump > testDB.sql\n$ sqlite3 testDB.db < testDB.sql\t# 恢复\n\n.exit\t# 退出\n```\n\n"}}]);